from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path
from typing import Final

ROOT: Final = Path(__file__).resolve().parents[1]
DEFAULT_RECORDS_DIR: Final = ROOT / "runs" / "bench" / "season-2-backfill"
DEFAULT_INDEX: Final = ROOT / "web" / "public" / "data" / "index.json"
DEFAULT_OUT: Final = ROOT / "web" / "public" / "data" / "agentic.json"
PROTOCOL_PATH: Final = ROOT / "protocol" / "index-v4.2.json"
SCHEMA: Final = "localbench-agentic-column/v2"
GENERATED_NOTE: Final = (
    "Generated by web/build_agentic.py from ranked season-2 records. "
    "AppWorld item verdicts in those records are authoritative; historical funnel series are not carried."
)


class AgenticBuildError(RuntimeError):
    pass


def main(argv: list[str] | None = None) -> int:
    args = _parse_args(sys.argv[1:] if argv is None else argv)
    try:
        payload = build_agentic(records_dir=args.records, index_path=args.index)
    except (AgenticBuildError, OSError, json.JSONDecodeError) as exc:
        print(f"build_agentic: {exc}", file=sys.stderr)
        return 2
    _write_json(args.out, payload)
    print(f"wrote {args.out} ({len(payload['models'])} models)")
    return 0


def build_agentic(*, records_dir: Path, index_path: Path) -> dict[str, object]:
    protocol = _read_object(PROTOCOL_PATH)
    agentic_protocol = _require_object(
        protocol.get("agentic_protocol"), "protocol.agentic_protocol"
    )
    denominator = _require_int(
        agentic_protocol.get("task_denominator"), "task_denominator"
    )
    subset_hash = _require_text(agentic_protocol.get("subset_sha256"), "subset_sha256")
    index = _read_object(index_path)
    rows = index.get("models")
    if not isinstance(rows, list):
        raise AgenticBuildError(f"{index_path}: models must be a list")

    rows_by_stem: dict[str, dict[str, object]] = {}
    for raw_row in rows:
        if not isinstance(raw_row, dict):
            continue
        run_id = raw_row.get("best_run_id")
        if isinstance(run_id, str) and "__" in run_id:
            rows_by_stem[run_id.rsplit("__", maxsplit=1)[1]] = raw_row

    models: dict[str, object] = {}
    finished_at: list[str] = []
    record_paths = sorted(records_dir.glob("*-s2v5.json"))
    if not record_paths:
        raise AgenticBuildError(f"{records_dir}: no ranked s2v5 records")
    for path in record_paths:
        record = _read_object(path)
        row = rows_by_stem.get(path.stem)
        if row is None:
            raise AgenticBuildError(
                f"{path.name}: no matching best_run_id in index.json"
            )
        slug = _require_text(row.get("slug"), f"{path.name}: slug")
        label = _require_text(row.get("model_label"), f"{path.name}: model_label")
        agentic_run = _require_object(
            record.get("agentic_run"), f"{path.name}: agentic_run"
        )
        if agentic_run.get("subset_hash") != subset_hash:
            raise AgenticBuildError(
                f"{path.name}: AppWorld subset hash differs from index-v4.2"
            )
        items = record.get("items")
        if not isinstance(items, list):
            raise AgenticBuildError(f"{path.name}: items must be a list")
        appworld = [
            item
            for item in items
            if isinstance(item, dict)
            and item.get("bench") == agentic_protocol.get("bench")
        ]
        if len(appworld) != denominator:
            raise AgenticBuildError(
                f"{path.name}: expected {denominator} AppWorld items, got {len(appworld)}"
            )
        if any(item.get("correct") not in (True, False) for item in appworld):
            raise AgenticBuildError(f"{path.name}: AppWorld verdict is missing")
        successes = sum(item.get("correct") is True for item in appworld)
        asr = successes / denominator
        models[slug] = {
            "asr": round(asr, 6),
            "asr_pct": round(asr * 100, 2),
            "n_tasks": denominator,
            "n_runs": 1,
            "asr_series": [round(asr, 6)],
            "label": label,
        }
        ended = record.get("run_finished_at")
        if isinstance(ended, str):
            finished_at.append(ended)

    return {
        "schema": SCHEMA,
        "generated_note": GENERATED_NOTE,
        "as_of": max(finished_at) if finished_at else None,
        "models": dict(sorted(models.items())),
    }


def _parse_args(argv: list[str]) -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Build AppWorld display data from ranked records"
    )
    parser.add_argument("--records", type=Path, default=DEFAULT_RECORDS_DIR)
    parser.add_argument("--index", type=Path, default=DEFAULT_INDEX)
    parser.add_argument("--out", type=Path, default=DEFAULT_OUT)
    return parser.parse_args(argv)


def _read_object(path: Path) -> dict[str, object]:
    value = json.loads(path.read_text(encoding="utf-8-sig"))
    if not isinstance(value, dict):
        raise AgenticBuildError(f"{path}: expected object")
    return value


def _require_object(value: object, where: str) -> dict[str, object]:
    if not isinstance(value, dict):
        raise AgenticBuildError(f"{where}: expected object")
    return value


def _require_text(value: object, where: str) -> str:
    if not isinstance(value, str) or not value:
        raise AgenticBuildError(f"{where}: expected non-empty string")
    return value


def _require_int(value: object, where: str) -> int:
    if isinstance(value, bool) or not isinstance(value, int):
        raise AgenticBuildError(f"{where}: expected integer")
    return value


def _write_json(path: Path, payload: object) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w", encoding="utf-8", newline="\n") as handle:
        json.dump(payload, handle, indent=2, sort_keys=True)
        handle.write("\n")


if __name__ == "__main__":
    raise SystemExit(main())
